mapper.update:
update monthk set update_time = now()

        , name = #{name}


        , open = #{open}


        , high = #{high}


        , low = #{low}


        , `close` = #{close}


        , prev_close = #{prevClose}


        , percent = #{percent}


        , volume = #{volume}


        , amount = #{amount}


        , ma5 = #{ma5}


        , ma10 = #{ma10}


        , ma20 = #{ma20}


        , ma30 = #{ma30}


        , ma60 = #{ma60}


        , ma120 = #{ma120}


        , dea = #{dea}


         , dif = #{dif}


        , macd = #{macd}


        , cross_params = #{crossParams}

      where code = #{code} and day = #{day}

mapper.select:
select d.* from monthk d where
d.code = #{code} and d.day < #{fromDay}
order by d.day desc limit 1

   	select m.code, m.day, m.open, m.`close`, m.prev_close, m.high, m.low, m.ma5, m.ma10, m.ma20, m.ma30, m.ma60, m.ma120, m.dea, m.dif, m.macd from monthk m


		  		and m.code = #{code}



				and (select count(*) from monthk where code=m.code and day > m.day) < #{nmonths}
